import UIKit

// MARK: - Network Configuration

enum ServerEnvironment {
    case api
    case legacy
    
    var baseURL: String {
        switch self {
        case .api:
            return "https://api.example.com"
        case .legacy:
            return "http://legacy.internal"
        }
    }
    
    var isSecure: Bool {
        switch self {
        case .api:
            return true
        case .legacy:
            return false
        }
    }
}

// MARK: - API Error

enum APIError: Error, LocalizedError {
    case invalidURL
    case networkError(Error)
    case invalidResponse
    case httpError(Int)
    case decodingError(Error)
    case noData
    case insecureConnectionBlocked
    
    var errorDescription: String? {
        switch self {
        case .invalidURL:
            return "Invalid URL"
        case .networkError(let error):
            return "Network error: \(error.localizedDescription)"
        case .invalidResponse:
            return "Invalid server response"
        case .httpError(let code):
            return "HTTP error: \(code)"
        case .decodingError(let error):
            return "Decoding error: \(error.localizedDescription)"
        case .noData:
            return "No data received"
        case .insecureConnectionBlocked:
            return "Insecure connection was blocked by ATS"
        }
    }
}

// MARK: - API Response Models

struct APIResponse<T: Decodable>: Decodable {
    let success: Bool
    let data: T?
    let message: String?
}

struct User: Codable {
    let id: Int
    let name: String
    let email: String
}

struct LegacyRecord: Codable {
    let recordId: String
    let value: String
    let timestamp: String
}

// MARK: - Network Session Manager

class NetworkSessionManager: NSObject, URLSessionDelegate {
    
    static let shared = NetworkSessionManager()
    
    private lazy var secureSession: URLSession = {
        let config = URLSessionConfiguration.default
        config.timeoutIntervalForRequest = 30
        config.timeoutIntervalForResource = 60
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        config.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "Accept": "application/json"
        ]
        return URLSession(configuration: config, delegate: self, delegateQueue: nil)
    }()
    
    private lazy var legacySession: URLSession = {
        let config = URLSessionConfiguration.default
        config.timeoutIntervalForRequest = 60
        config.timeoutIntervalForResource = 120
        config.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "Accept": "application/json"
        ]
        return URLSession(configuration: config, delegate: self, delegateQueue: nil)
    }()
    
    func session(for environment: ServerEnvironment) -> URLSession {
        switch environment {
        case .api:
            return secureSession
        case .legacy:
            return legacySession
        }
    }
    
    // MARK: - URLSessionDelegate
    
    func urlSession(_ session: URLSession,
                    didReceive challenge: URLAuthenticationChallenge,
                    completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        
        guard let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        let host = challenge.protectionSpace.host
        
        if host == "api.example.com" {
            // For the secure API, perform standard certificate validation
            completionHandler(.performDefaultHandling, nil)
        } else if host.hasSuffix("legacy.internal") {
            // For legacy internal systems, accept the server trust
            // In production, you'd want to pin certificates or use a custom CA
            let credential = URLCredential(trust: serverTrust)
            completionHandler(.useCredential, credential)
        } else {
            completionHandler(.performDefaultHandling, nil)
        }
    }
}

// MARK: - API Client

class APIClient {
    
    static let shared = APIClient()
    
    private let sessionManager = NetworkSessionManager.shared
    private var authToken: String?
    
    private init() {}
    
    func setAuthToken(_ token: String) {
        self.authToken = token
    }
    
    // MARK: - Generic Request
    
    func request<T: Decodable>(
        environment: ServerEnvironment,
        path: String,
        method: String = "GET",
        body: Data? = nil,
        headers: [String: String]? = nil
    ) async throws -> T {
        
        let urlString = "\(environment.baseURL)\(path)"
        
        guard let url = URL(string: urlString) else {
            throw APIError.invalidURL
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.httpBody = body
        
        // Add auth token if available
        if let token = authToken {
            request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        // Add custom headers
        headers?.forEach { key, value in
            request.setValue(value, forHTTPHeaderField: key)
        }
        
        // Log warning for insecure connections
        if !environment.isSecure {
            print("⚠️ WARNING: Making insecure HTTP request to \(urlString)")
        }
        
        let session = sessionManager.session(for: environment)
        
        do {
            let (data, response) = try await session.data(for: request)
            
            guard let httpResponse = response as? HTTPURLResponse else {
                throw APIError.invalidResponse
            }
            
            guard (200...299).contains(httpResponse.statusCode) else {
                throw APIError.httpError(httpResponse.statusCode)
            }
            
            do {
                let decoder = JSONDecoder()
                decoder.keyDecodingStrategy = .convertFromSnakeCase
                let result = try decoder.decode(T.self, from: data)
                return result
            } catch {
                throw APIError.decodingError(error)
            }
        } catch let error as APIError {
            throw error
        } catch {
            // Check if the error is an ATS-related error
            let nsError = error as NSError
            if nsError.domain == NSURLErrorDomain &&
                (nsError.code == NSURLErrorAppTransportSecurityRequiresSecureConnection ||
                 nsError.code == NSURLErrorSecureConnectionFailed) {
                throw APIError.insecureConnectionBlocked
            }
            throw APIError.networkError(error)
        }
    }
    
    // MARK: - Secure API Methods
    
    func fetchUsers() async throws -> [User] {
        let response: APIResponse<[User]> = try await request(
            environment: .api,
            path: "/v1/users"
        )
        guard let users = response.data else {
            throw APIError.noData
        }
        return users
    }
    
    func fetchUser(id: Int) async throws -> User {
        let response: APIResponse<User> = try await request(
            environment: .api,
            path: "/v1/users/\(id)"
        )
        guard let user = response.data else {
            throw APIError.noData
        }
        return user
    }
    
    func createUser(_ user: User) async throws -> User {
        let encoder = JSONEncoder()
        encoder.keyEncodingStrategy = .convertToSnakeCase
        let body = try encoder.encode(user)
        
        let response: APIResponse<User> = try await request(
            environment: .api,
            path: "/v1/users",
            method: "POST",
            body: body
        )
        guard let createdUser = response.data else {
            throw APIError.noData
        }
        return createdUser
    }
    
    // MARK: - Legacy System Methods
    
    func fetchLegacyRecords() async throws -> [LegacyRecord] {
        let response: APIResponse<[LegacyRecord]> = try await request(
            environment: .legacy,
            path: "/records"
        )
        guard let records = response.data else {
            throw APIError.noData
        }
        return records
    }
    
    func fetchLegacyRecord(id: String) async throws -> LegacyRecord {
        let response: APIResponse<LegacyRecord> = try await request(
            environment: .legacy,
            path: "/records/\(id)"
        )
        guard let record = response.data else {
            throw APIError.noData
        }
        return record
    }
    
    func updateLegacyRecord(_ record: LegacyRecord) async throws -> LegacyRecord {
        let encoder = JSONEncoder()
        encoder.keyEncodingStrategy = .convertToSnakeCase
        let body = try encoder.encode(record)
        
        let response: APIResponse<LegacyRecord> = try await request(
            environment: .legacy,
            path: "/records/\(record.recordId)",
            method: "PUT",
            body: body
        )
        guard let updatedRecord = response.data else {
            throw APIError.noData
        }
        return updatedRecord
    }
    
    // MARK: - Connection Test
    
    func testConnection(to environment: ServerEnvironment) async -> (success: Bool, message: String) {
        let urlString = "\(environment.baseURL)/health"
        
        guard let url = URL(string: urlString) else {
            return (false, "Invalid URL")
        }
        
        let session = sessionManager.session(for: environment)
        
        do {
            let (_, response) = try await session.data(from: url)
            
            if let httpResponse = response as? HTTPURLResponse {
                let success = (200...299).contains(httpResponse.statusCode)
                return (success, "Status: \(httpResponse.statusCode)")
            }
            return (false, "Invalid response")
        } catch {
            let nsError = error as NSError
            if nsError.code == NSURLErrorAppTransportSecurityRequiresSecureConnection {
                return (false, "Blocked by App Transport Security. Check Info.plist exceptions.")
            }
            return (false, error.localizedDescription)
        }
    }
}

// MARK: - ATS Configuration Validator

class ATSConfigurationValidator {
    
    static func validateConfiguration() {
        print("🔒 ATS Configuration Validation")
        print("================================")
        
        guard let infoDict = Bundle.main.infoDictionary,
              let atsDict = infoDict["NSAppTransportSecurity"] as? [String: Any] else {
            print("❌ No ATS configuration found in Info.plist")
            return
        }
        
        // Check if arbitrary loads are enabled
        if let allowsArbitraryLoads = atsDict["NSAllowsArbitraryLoads"] as? Bool {
            if allowsArbitraryLoads {
                print("⚠️ NSAllowsArbitraryLoads is TRUE - All insecure connections allowed")
            } else {
                print("✅ NSAllowsArbitraryLoads is FALSE - Secure by default")
            }
        }
        
        // Check exception domains
        if let exceptionDomains = atsDict["NSExceptionDomains"] as? [String: Any] {
            print("\n📋 Exception Domains:")
            
            for (domain, config) in exceptionDomains {
                print("\n  Domain: \(domain)")
                
                if let domainConfig = config as? [String: Any] {
                    if let allowsInsecure = domainConfig["NSExceptionAllowsInsecureHTTPLoads"] as? Bool {
                        let icon = allowsInsecure ? "⚠️" : "✅"
                        print("    \(icon) Allows Insecure HTTP: \(allowsInsecure)")
                    }
                    
                    if let requiresFS = domainConfig["NSExceptionRequiresForwardSecrecy"] as? Bool {
                        let icon = requiresFS ? "✅" : "⚠️"
                        print("    \(icon) Requires Forward Secrecy: \(requiresFS)")
                    }
                    
                    if let minTLS = domainConfig["NSExceptionMinimumTLSVersion"] as? String {
                        let icon = minTLS == "TLSv1.2" ? "✅" : "⚠️"
                        print("    \(icon) Minimum TLS Version: \(minTLS)")
                    }
                    
                    if let includesSubdomains = domainConfig["NSIncludesSubdomains"] as? Bool {
                        print("    ℹ️ Includes Subdomains: \(includesSubdomains)")
                    }
                }
            }
        }
        
        print("\n================================")
    }
}

// MARK: - View Model

@MainActor
class MainViewModel: ObservableObject {
    @Published var users: [User] = []
    @Published var legacyRecords: [LegacyRecord] = []
    @Published var apiConnectionStatus: String = "Not tested"
    @Published var legacyConnectionStatus: String = "Not tested"
    @Published var isLoading = false
    @Published var errorMessage: String?
    
    private let apiClient = APIClient.shared
    
    func testConnections() async {
        isLoading = true
        errorMessage = nil
        
        let apiResult = await apiClient.testConnection(to: .api)
        apiConnectionStatus = apiResult.success ? "✅ Connected" : "❌ \(apiResult.message)"
        
        let legacyResult = await apiClient.testConnection(to: .legacy)
        legacyConnectionStatus = legacyResult.success ? "✅ Connected" : "❌ \(legacyResult.message)"
        
        isLoading = false
    }
    
    func loadUsers() async {
        isLoading = true
        errorMessage = nil
        
        do {
            users = try await apiClient.fetchUsers()
        } catch {
            errorMessage = error.localizedDescription
        }
        
        isLoading = false
    }
    
    func loadLegacyRecords() async {
        isLoading = true
        errorMessage = nil
        
        do {
            legacyRecords = try await apiClient.fetchLegacyRecords()
        } catch {
            errorMessage = error.localizedDescription
        }
        
        isLoading = false
    }
}

